// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  var count = 0;
  var count1 = 0;
  // 필수항목 체크 
  if (!$c.gus.cfValidate($p, [ed_cvsslMgntNo, ed_clntNo, acb_adjmStdCd])) {
    return;
  }
  for (var i = 0; i <= ds_orderEachPaymentCommissionInfo.getRowCount(); i++) {
    if (ds_orderEachPaymentCommissionInfo.getRowStatus(i) == "D") {
      count1++;
      break;
    }
  }
  if (scwin.firstCheck1 != 1) {
    for (var i = 0; i <= ds_orderEachPaymentCommissionInfo.getRowCount(); i++) {
      if (ds_orderEachPaymentCommissionInfo.getCellData(i, "odrNo") != "") {
        if (ds_orderEachPaymentCommissionInfo.getCellData(i, "ctrlPayCmis") == ds_orderEachPaymentCommissionInfo.getOriginalCellData(i, "ctrlPayCmis") && ds_orderEachPaymentCommissionInfo.getCellData(i, "payCmis") == ds_orderEachPaymentCommissionInfo.getOriginalCellData(i, "payCmis") && ds_orderEachPaymentCommissionInfo.getCellData(i, "rmk") == ds_orderEachPaymentCommissionInfo.getOriginalCellData(i, "rmk")) {
          scwin.firstCheck1 = 0;
        } else {
          scwin.firstCheck1 = 1;
          break;
        }
      }
    }
  }

  //if(!ds_orderEachPaymentCommissionInfo.IsUpdated && firstCheck1==0 ) {
  if (scwin.firstCheck1 == 0 && count1 <= 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["오더별 지급수수료"]);
    return false;
  }
  for (var i = 0; i <= ds_orderEachPaymentCommissionInfo.getRowCount(); i++) {
    if (ds_orderEachPaymentCommissionInfo.getCellData(i, "chk") == "1") {
      //if(!ds_orderEachPaymentCommissionInfo.IsUpdated && ds_orderEachPaymentCommissionInfo.NameValue(i,"payCmis")==0 && ds_orderEachPaymentCommissionInfo.NameValue(i,"ctrlPayCmis")==0 ){
      if (ds_orderEachPaymentCommissionInfo.getCellData(i, "payCmis") == 0 && ds_orderEachPaymentCommissionInfo.getCellData(i, "ctrlPayCmis") == "0") {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["지급수수료"]);
        return false;
      }
    }
  }

  /*for(var i=1; i<=ds_orderEachPaymentCommissionInfo.CountRow; i++){
  	if(ds_orderEachPaymentCommissionInfo.SysStatus(i)==3 && ds_orderEachPaymentCommissionInfo.NameValue(i,"chk")==0){
  		cfAlertMsg(MSG_CM_WRN_007,["수정할 데이터의 오더번호"]);
  		return false;
  	}
  }*/

  for (var i = 0; i <= ds_orderEachPaymentCommissionInfo.getRowCount(); i++) {
    if (ds_orderEachPaymentCommissionInfo.getCellData(i, "chk") == "1" && ds_orderEachPaymentCommissionInfo.getCellData(i, "odrNo") != "" && ds_orderEachPaymentCommissionInfo.getCellData(i, "payCmis") == "0" && ds_orderEachPaymentCommissionInfo.getCellData(i, "ctrlPayCmis") == "0" && ds_orderEachPaymentCommissionInfo.getCellData(i, "rmk") == "") {
      await $c.win.alert($p, i + "번째 데이터는 변경된 사항이 없습니다. 선택된 체크박스를 해제해 주십시오.");
      return false;
    }
  }
  for (var i = 0; i <= ds_orderEachPaymentCommissionInfo.getRowCount(); i++) {
    if (ds_orderEachPaymentCommissionInfo.getCellData(i, "payCmis") <= 0 && ds_orderEachPaymentCommissionInfo.getCellData(i, "ctrlPayCmis") > 0) {
      $c.win.alert($p, "먼저 지급수수료를 계산해 주십시오.");
      return false;
    }
  }
  ds_paymentCommissionBasisInfo.setCellData(0, "clntNo", ed_clntNo.getValue());
  ds_paymentCommissionBasisInfo.setCellData(0, "adjmStdCd", acb_adjmStdCd.getValue());
  if (scwin.firstCheck != 1 && ds_paymentCommissionBasisInfo.getOriginalCellData(0, "clntNo") == ds_paymentCommissionBasisInfo.getCellData(0, "clntNo")) {
    ds_paymentCommissionBasisInfo.setCellData(0, "clntNm", ds_paymentCommissionBasisInfo.getCellData(0, "clntNm") + " ");
  } else {
    ds_paymentCommissionBasisInfo.modifyRowStatus(i, 'R');
  }
  for (var i = 0; i <= ds_orderEachPaymentCommissionInfo.getRowCount(); i++) {
    if (ds_orderEachPaymentCommissionInfo.getCellData(i, "chk") == "1" && ds_orderEachPaymentCommissionInfo.getCellData(i, "extYn") == "N") {
      // 오더별 하역지급수수료 테이블에 자료가 없으면 
      ds_orderEachPaymentCommissionInfo.modifyRowStatus(i, 'R');
    }
  }
  for (var i = 0; i <= ds_orderEachPaymentCommissionInfo.getRowCount(); i++) {
    if (ds_orderEachPaymentCommissionInfo.getCellData(i, "chk") == "1") {
      count++;
      break;
    }
  }

  //작업일자 셋팅
  if (!(await scwin.f_setRsltsStdDt())) {
    return;
  }
  for (var i = 0; i < ds_carryingVesselCompletionInformation.getRowCount(); i++) {
    ed_impExpClsNm.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "impExpClsNm"));
    ed_cvsslWrkCompleteYn.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteYn"));
    ed_cvsslWrkCompleteDt.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt"));
  }
  if (count <= 0 && count1 <= 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_056, ["오더번호"]);
    return false;
  } else {
    let rtn = await $c.win.confirm($p, "저장하시겠습니까");
    if (rtn) {
      let objSubmit = await $c.sbm.execute($p, sbm_save);
      if (objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_save_submitDone();
      }
    }
  }
};

//-------------------------------------------------------------------------
// 작업완료일자 셋팅
//------------------------------------------------------------------------- 
//-------------------------------------------------------------------------
scwin.f_setRsltsStdDt = async function () {
  //실적기준일자 셋팅 , 20060607 김상철 ppc
  // . 수출입 확인
  var checkImp = "";
  var checkDateSetting = "";
  for (var i = 0; i <= ds_orderEachPaymentCommissionInfo.getRowCount(); i++) {
    if (ds_orderEachPaymentCommissionInfo.getRowStatus(i) != "D") {
      //삭제가 아닐경우

      if (ds_orderEachPaymentCommissionInfo.getCellData(i, "chk") == "1" && ds_orderEachPaymentCommissionInfo.getCellData(i, "odrNo") != "") {
        var check = ds_orderEachPaymentCommissionInfo.getCellData(i, "rsltsStdDt");
        if (check == "") {
          //alert(" 수출입 구분 첫번째  >> "+ds_orderEachPaymentCommissionInfo.NameValue(i,"impExpDomesticClsCd"));
          if (ds_orderEachPaymentCommissionInfo.getCellData(i, "impExpDomesticClsCd") == "수입") {
            checkImp = "T";
          } else {
            checkImp = "F";
          }
          if (checkImp == "T") {
            //수입일 경우 
            for (var j = 0; j <= ds_carryingVesselCompletionInformation.getRowCount(); j++) {
              if (ds_orderEachPaymentCommissionInfo.getCellData(i, "chk") == "1") {
                ed_impExpClsNm.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "impExpClsNm"));
                ed_cvsslWrkCompleteYn.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteYn"));
                ed_cvsslWrkCompleteDt.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt"));
                //alert(" 수출입 구분"+impExpClsNm);
                //alert(" 본선완료여부"+cvsslWrkCompleteYn);
                //alert(" 작업 완료 일자"+cvsslWrkCompleteDt);
                if (ed_cvsslWrkCompleteYn.getValue() == "1" && ds_orderEachPaymentCommissionInfo.getCellData(i, "impExpDomesticClsCd") == ed_impExpClsNm.getValue()) {
                  ds_orderEachPaymentCommissionInfo.setCellData(i, "rsltsStdDt", ed_cvsslWrkCompleteDt.getValue());
                } else {
                  await $c.gus.cfAlertMsg($p, " 수입 구분이 다르거나 , 본선 완료가 되지 않았습니다.");
                  return false;
                }
              }
            }
          } else if (checkImp == "F") {
            //수입이 아닐경우

            for (var j = 0; j <= ds_carryingVesselCompletionInformation.getRowCount(); j++) {
              if (ds_orderEachPaymentCommissionInfo.getCellData(i, "chk") == "1") {
                ed_impExpClsNm.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "impExpClsNm"));
                ed_cvsslWrkCompleteYn.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteYn"));
                ed_cvsslWrkCompleteDt.setValue(ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt"));
                if (ed_cvsslWrkCompleteYn.getValue() == "1" && ds_orderEachPaymentCommissionInfo.getCellData(i, "impExpDomesticClsCd") == "수출") {
                  ds_orderEachPaymentCommissionInfo.setCellData(i, "rsltsStdDt", ed_cvsslWrkCompleteDt.getValue());
                } else {
                  await $c.win.cfAlertMsg($p, " 수출 구분이 다르거나 , 본선 완료가 되지 않았습니다.");
                  return false;
                }
              }
            }
          }
        }
      }
    }
  }
  return true;
};

