scwin.f_Caculate = async function () {
  var count1 = 0;
  var count = ds_orderEachPaymentCommissionInfo.getRowCount();

  // 필수항목 체크 
  if (!(await $c.gus.cfValidate($p, [ed_cvsslMgntNo, ed_clntNo, acb_adjmStdCd]))) {
    return;
  }
  ;
  for (var i = 0; i < ds_orderEachPaymentCommissionInfo.getRowCount(); i++) {
    if (ds_orderEachPaymentCommissionInfo.getCellData(i, "chk") == "1") {
      count1++;
      break;
    }
  }
  ;
  if (count1 == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ["오더번호"]);
    return false;
  }
  ;
  ds_paymentCommissionBasisInfo.insertRow();
  ds_paymentCommissionBasisInfo.setCellData(ds_paymentCommissionBasisInfo.getRowCount() - 1, "clntNo", ed_clntNo.getValue());
  ds_paymentCommissionBasisInfo.setCellData(ds_paymentCommissionBasisInfo.getRowCount() - 1, "adjmStdCd", acb_adjmStdCd.getValue());

  //처리 날짜 setting
  for (var i = 0; i <= ds_carryingVesselCompletionInformation.getRowCount(); i++) {
    var checkDate = ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt");
    if (checkDate == "") {} else {
      scwin.workEndDt = ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt");
      break;
    }
  }
  ;
  checkDate = "";
  for (var i = 0; i <= ds_orderEachPaymentCommissionInfo.getRowCount(); i++) {
    if (ds_orderEachPaymentCommissionInfo.getCellData(i, "chk") == "1") {
      checkDate = ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt");
      if (checkDate == "") {
        ds_carryingVesselCompletionInformation.setCellData(0, "cvsslWrkCompleteDt", scwin.workEndDt);
      }
    }
  }
  for (var i = 0; i <= ds_orderEachPaymentCommissionInfo.getRowCount(); i++) {
    if (ds_orderEachPaymentCommissionInfo.getCellData(i, "chk") == "1") {
      if (count > 0) {
        ds_orderEachPaymentCommissionInfo.setCellData(i, "commNm", ds_orderEachPaymentCommissionInfo.getCellData(i, "commNm"));
      } else {
        ds_orderEachPaymentCommissionInfo.modifyRowStatus(i, "C");
      }
      if (ds_paymentCommissionBasisInfo.getCellData(0, "clntNo") == ds_paymentCommissionBasisInfo.getCellData(0, "clntNo")) {
        ds_paymentCommissionBasisInfo.setCellData(0, "clntNm", ds_paymentCommissionBasisInfo.getCellData(0, "clntNm") + " ");
      }
      ed_clntNo1.setValue(ed_clntNo.getValue());
    }
  }
  dma_condition.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());
  dma_condition.set("payCmisKnd", acb_payCmisKnd.getValue());
  dma_condition.set("payCmisKndRpc", acb_payCmisKnd.getValue());
  await $c.sbm.execute($p, sbm_caculate);
};
scwin.f_Caculate1 = async function (row, chkCount) {
  var chkCount = chkCount - 1;
  var payClsCd = "";
  if (acb_payCmisKnd.getValue() == "1") {
    payClsCd = "위탁하역료(수출)";
  } else if (acb_payCmisKnd.getValue() == "2") {
    payClsCd = "선석사용료(수입)";
  } else if (acb_payCmisKnd.getValue() == "4") {
    payClsCd = "고박료";
  } else if (acb_payCmisKnd.getValue() == "5") {
    payClsCd = "선석사용료";
  } else if (acb_payCmisKnd.getValue() == "6") {
    payClsCd = "화물입항료";
  } else if (acb_payCmisKnd.getValue() == "7") {
    payClsCd = "화물입항료(기계화)";
  }
  ;
  var rowCount = row + 1;
  if (ds_caculatePaymentBasisInfo.getCellData(chkCount, "uprKnd") == "0") {
    await $c.gus.cfAlertMsg($p, rowCount + "번재 데이터의 " + payClsCd + "의 요율이 없습니다.");
    scwin.firstCheck1 = 0;
    return false;
  } else if (ds_caculatePaymentBasisInfo.getCellData(chkCount, "uprKnd") == "1") {
    await $c.gus.cfAlertMsg($p, rowCount + "번재 데이터의 " + payClsCd + "의 공통요율이 없습니다.");
    scwin.firstCheck1 = 0;
    return false;
  } else if (ds_caculatePaymentBasisInfo.getCellData(chkCount, "uprKnd") == "2") {
    await $c.gus.cfAlertMsg($p, rowCount + "번재 데이터의 " + payClsCd + "의 협정요율이 없습니다.");
    scwin.firstCheck1 = 0;
    return false;
  } else if (ds_caculatePaymentBasisInfo.getCellData(chkCount, "uprKnd") == "3") {
    if (ds_caculatePaymentBasisInfo.getCellData(chkCount, "ctrtEndDt") < scwin.dateStr) {
      await $c.gus.cfAlertMsg($p, payClsCd + "의 요율은 계약기간이 만료되었습니다.");
      scwin.firstCheck1 = 0;
      return false;
    }
  }
  if (acb_adjmStdCd.getValue() == "O") {
    //오더물량
    if (ds_orderEachPaymentCommissionInfo.getCellData(row, "upperCd") == "01") {
      // 상위단위코드가 수량이면 
      ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", ds_orderEachPaymentCommissionInfo.getCellData(row, "qty") * ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr"));
    } else if (ds_orderEachPaymentCommissionInfo.getCellData(row, "upperCd") == "02") {
      // 상위단위코드가 중량이면 
      if (ds_caculatePaymentBasisInfo.getCellData(chkCount, "unitCd") == "KG") {
        ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "grossWt")) * Number(ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr")) * 1000);
      } else {
        ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "grossWt")) * Number(ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr")));
      }
    } else if (ds_orderEachPaymentCommissionInfo.getCellData(row, "upperCd") == "04") {
      // 상위단위코드가 용적이면 
      if (ds_caculatePaymentBasisInfo.getCellData(chkCount, "unitCd") == "R/T") {
        if (Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "grossWt")) > Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "cbm"))) {
          ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "grossWt")) * Number(ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr")));
        } else {
          ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "cbm")) * Number(ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr")));
        }
      } else if (ds_caculatePaymentBasisInfo.getCellData(chkCount, "unitCd") == "RNT") {
        var v_Cbm = scwin.f_Round(Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "cbm")) / 1.133, 3, 'F');
        if (Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "grossWt")) > v_Cbm) {
          ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "grossWt")) * Number(ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr")));
        } else {
          ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", v_Cbm * Number(ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr")));
        }
      } else if (ds_caculatePaymentBasisInfo.getCellData(chkCount, "unitCd") == "CBM") {
        ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "grossCbm")) * Number(ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr")));
      }
    }
  } else if (acb_adjmStdCd.getValue() == "A") {
    // 협정물량 
    if (ds_orderEachPaymentCommissionInfo.getCellData(row, "upperCd") == "01") {
      // 상위단위코드가 수량이면 
      ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "agrQty")) * Number(ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr")));
    } else if (ds_orderEachPaymentCommissionInfo.getCellData(row, "upperCd") == "02") {
      // 상위단위코드가 중량이면
      if (ds_caculatePaymentBasisInfo.getCellData(chkCount, "unitCd") == "KG") {
        ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "agrWt")) * Number(ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr") * 1000));
      } else {
        ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "agrWt")) * Number(ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr")));
      }
    } else if (ds_orderEachPaymentCommissionInfo.getCellData(row, "upperCd") == "04") {
      // 상위단위코드가 용적이면 
      if (ds_caculatePaymentBasisInfo.getCellData(chkCount, "unitCd") == "R/T") {
        if (Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "agrWt")) > Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "agrcbm"))) {
          ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "agrWt")) * Number(ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr")));
        } else {
          ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "agrcbm")) * Number(ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr")));
        }
      } else if (ds_caculatePaymentBasisInfo.getCellData(chkCount, "unitCd") == "RNT") {
        var v_Cbm = scwin.f_Round(Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "agrcbm") / 1.133), 3, 'F');
        if (Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "agrWt")) > v_Cbm) {
          ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "agrWt")) * Number(ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr")));
        } else {
          ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", v_Cbm * ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr"));
        }
      } else if (ds_caculatePaymentBasisInfo.getCellData(0, "unitCd") == "CBM") {
        ds_orderEachPaymentCommissionInfo.setCellData(row, "payCmis", Number(ds_orderEachPaymentCommissionInfo.getCellData(row, "agrCbm")) * Number(ds_caculatePaymentBasisInfo.getCellData(0, "upr")));
      }
    }
  }
  ds_orderEachPaymentCommissionInfo.setCellData(row, "upr", ds_caculatePaymentBasisInfo.getCellData(chkCount, "upr"));
  scwin.firstCheck1 = 1;
};

//-------------------------------------------------------------------------
// 금액 반올림
//-------------------------------------------------------------------------
scwin.f_Round = async function (Num, Position, Base) {
  // Num = 반올림할 수
  // Position = 반올림할 자릿수(정수로만)
  // Base = i 이면 소숫점위의 자릿수에서, f 이면 소숫점아래의 자릿수에서 반올림

  if (Position == 0) {
    // 1이면 소숫점1 자리에서 반올림
    return Math.round(Num);
  } else if (Position > 0) {
    var cipher = '1';
    for (var i = 0; i < Position; i++) cipher = cipher + '0';
    var no = Number(cipher);
    if (Base == "F") {
      // 소숫점아래에서 반올림                        
      return Math.round(Num * no) / no;
    } else {
      // 소숫점위에서 반올림.                        
      return Math.round(Num / no) * no;
    }
  } else {
    await $c.gus.cfAlertMsg($p, "자릿수는 정수로만 구분합니다.");
    return false;
  }
};

